query:
-- Total games in DB
SELECT COUNT(*) as total_games FROM games;

-- Games by date
SELECT game_date, COUNT(*) as count FROM games GROUP BY game_date ORDER BY game_date;

-- Games with TBD start times
SELECT COUNT(*) as tbd_count FROM games WHERE start_time_est = 'TBD' OR start_time_est IS NULL;

-- Games with live VSiN odds
SELECT COUNT(*) as with_odds FROM games WHERE away_book_spread IS NOT NULL OR book_total IS NOT NULL;

